示例（保持语义，展示关键结构；实际块大小需按缓存调参）：

// 建议添加 restrict/对齐（见后续条目）
const int BI=32, BJ=64, BK=32;
for (int ii=0; ii<_PB_NI; ii+=BI)
  for (int jj=0; jj<_PB_NJ; jj+=BJ) {
    // 初始化 tmp block
    for (int i=ii; i<min(ii+BI,_PB_NI); ++i)
      for (int j=jj; j<min(jj+BJ,_PB_NJ); ++j)
        tmp[i][j] = 0;

    for (int kk=0; kk<_PB_NK; kk+=BK) {
      // 可选：pack B[kk:kk+BK][jj:jj+BJ] 到连续缓冲 Bp[k][j]
      // for k,j: Bp[(k-kk)*BJ+(j-jj)] = B[k][j];

      for (int i=ii; i<min(ii+BI,_PB_NI); ++i)
        for (int k=kk; k<min(kk+BK,_PB_NK); ++k) {
          DATA_TYPE a = alpha * A[i][k];
          #pragma omp simd
          for (int j=jj; j<min(jj+BJ,_PB_NJ); ++j)
            tmp[i][j] += a * B[k][j]; // 若 pack，则改为 Bp[(k-kk)*BJ+(j-jj)]
        }
    }
  }

并行：
#pragma omp parallel for collapse(2) schedule(static)
for (ii...) for (jj...) { ... }

示例结构：

const int BI=32, BJ=64, BK=32; // 这里 BK 对应原 nj
for (int ii=0; ii<_PB_NI; ii+=BI)
  for (int jj=0; jj<_PB_NL; jj+=BJ) {
    // 先对 D block 做 beta 缩放（只做一次）
    for (int i=ii; i<min(ii+BI,_PB_NI); ++i)
      for (int j=jj; j<min(jj+BJ,_PB_NL); ++j)
        D[i][j] *= beta;

    for (int kk=0; kk<_PB_NJ; kk+=BK) {
      // 可选 pack C[kk:kk+BK][jj:jj+BJ]
      for (int i=ii; i<min(ii+BI,_PB_NI); ++i)
        for (int k=kk; k<min(kk+BK,_PB_NJ); ++k) {
          DATA_TYPE t = tmp[i][k];
          #pragma omp simd
          for (int j=jj; j<min(jj+BJ,_PB_NL); ++j)
            D[i][j] += t * C[k][j];
        }
    }
  }

并行同样可对 (ii,jj) collapse(2)。

思路：以块为单位计算 tmp_block = alpha*A_block*B_block，然后立刻用于更新 D_block += tmp_block*C_block；不把 tmp 写回到大数组。
伪代码（块级融合）：
for ii,jj (D block)
  Dblock *= beta
  for kkB (over nj)  // C 的 k
    // 需要 tmp(i,kkB) = sum over nk of alpha*A(i,nk)*B(nk,kkB)
    // 在小块内先算 tmp_block(i,kc)（kc 为 kkB..kkB+BK）
    // 然后 Dblock += tmp_block * C_block

实现上通常需要两级 blocking + 小矩阵乘微内核；复杂度较高，但可显著减少 tmp 的内存流量。
